      console.error("Error fetching metrics:", error);
      res.status(500).json({ message: "Failed to fetch metrics" });
    }
  });

  app.get('/api/analytics/content-performance', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const brandDna = await storage.getBrandDna(userId);
      const content = await storage.getContent(userId, 30);

      if (!brandDna) {
        return res.status(400).json({ message: "Brand DNA not configured." });
      }

      const analysis = await analyzeContentPerformance(content, {
        // New comprehensive fields
        businessType: brandDna.businessType,
        businessModel: brandDna.businessModel,
        revenueUrgency: brandDna.revenueUrgency,
        targetAudience: brandDna.targetAudience,
        corePainPoint: brandDna.corePainPoint,
        audienceAspiration: brandDna.audienceAspiration,
        authorityLevel: brandDna.authorityLevel,
        communicationStyle: brandDna.communicationStyle,
        uniquePositioning: brandDna.uniquePositioning,
        platformPriority: brandDna.platformPriority,
        currentPresence: brandDna.currentPresence,
        primaryGoal: brandDna.primaryGoal,
        contentBandwidth: brandDna.contentBandwidth,
        successDefinition: brandDna.successDefinition,
        currentChallenges: brandDna.currentChallenges || undefined,
        pastSuccess: brandDna.pastSuccess || undefined,
        inspiration: brandDna.inspiration || undefined,

        // Legacy fields for backward compatibility
        tone: brandDna.tone,
        contentPillars: brandDna.contentPillars || [],
        audience: brandDna.audience || "",
        painPoints: brandDna.painPoints || [],
        desires: brandDna.desires || [],
        offer: brandDna.offer || "",
        businessGoal: brandDna.businessGoal || "",
      });

      res.json(analysis);
    } catch (error) {
      console.error("Error analyzing content performance:", error);
      res.status(500).json({ message: "Failed to analyze content performance" });
    }
  });

  // Strategy routes
  app.get('/api/strategy/report', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { week } = req.query;
      const report = await storage.getStrategyReport(userId, week as string);
      res.json(report);
    } catch (error) {
      console.error("Error fetching strategy report:", error);
      res.status(500).json({ message: "Failed to fetch strategy report" });
    }
  });

  app.post('/api/strategy/generate', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const brandDna = await storage.getBrandDna(userId);

      if (!brandDna) {
        return res.status(400).json({ message: "Brand DNA not configured. Please complete onboarding first." });
      }

      // Get current week data
      const currentWeek = new Date().toISOString().slice(0, 7) + "-W" + Math.ceil(new Date().getDate() / 7);
      const weeklyMetrics = await storage.getMetrics(userId, currentWeek);
      const content = await storage.getContent(userId, 20);
      const outreach = await storage.getOutreachMessages(userId);

      const aiResponse = await generateStrategyInsights({
        brandDna: {
          // New comprehensive fields
          businessType: brandDna.businessType,
          businessModel: brandDna.businessModel,
          revenueUrgency: brandDna.revenueUrgency,
          targetAudience: brandDna.targetAudience,
          corePainPoint: brandDna.corePainPoint,
          audienceAspiration: brandDna.audienceAspiration,
          authorityLevel: brandDna.authorityLevel,
          communicationStyle: brandDna.communicationStyle,
          uniquePositioning: brandDna.uniquePositioning,
          platformPriority: brandDna.platformPriority,
          currentPresence: brandDna.currentPresence,
          primaryGoal: brandDna.primaryGoal,
          contentBandwidth: brandDna.contentBandwidth,
          successDefinition: brandDna.successDefinition,
          currentChallenges: brandDna.currentChallenges || undefined,
          pastSuccess: brandDna.pastSuccess || undefined,
          inspiration: brandDna.inspiration || undefined,

          // Legacy fields for backward compatibility
          tone: brandDna.tone,
          contentPillars: brandDna.contentPillars || [],
          audience: brandDna.audience || "",
          painPoints: brandDna.painPoints || [],
          desires: brandDna.desires || [],
          offer: brandDna.offer || "",
          businessGoal: brandDna.businessGoal || "",
        },
        weeklyMetrics: weeklyMetrics || {},
        contentPerformance: content,
        outreachPerformance: outreach,
        currentGoals: {}, // TODO: implement goal tracking
      });

      // Save the strategy report
      const report = await storage.createStrategyReport({
        userId,
        week: currentWeek,
        focus: aiResponse.weeklyFocus,
        reasoning: aiResponse.insights.join(" "),
        recommendations: aiResponse.recommendations,
        weeklyPlan: aiResponse.nextWeekPlan,
      });

      res.json({ ...aiResponse, report });
    } catch (error) {
      console.error("Error generating strategy insights:", error);
      res.status(500).json({ message: "Failed to generate strategy insights" });
    }
  });

  // Company research routes
  app.post('/api/company/research', isAuthenticated, async (req: any, res) => {
    try {
      const { businessName, website, linkedinProfile, instagramHandle } = req.body;
      const analysis = await companyResearchService.analyzeCompanyOnlinePresence(
        businessName, website, linkedinProfile, instagramHandle
      );
      res.json(analysis);
    } catch (error) {
      console.error("Company research error:", error);
      res.status(500).json({ message: "Failed to analyze company presence" });
    }
  });

  // Social media integration routes
  app.post('/api/social/connect/:platform', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { platform } = req.params;
      const { accessToken, accessSecret } = req.body;

      let credentials;
      if (platform === 'instagram') {
        credentials = await socialMediaService.connectInstagramBusiness(accessToken);
      } else if (platform === 'linkedin') {
        credentials = await socialMediaService.connectLinkedIn(accessToken);
      } else if (platform === 'twitter') {
        credentials = await socialMediaService.connectTwitter(accessToken, accessSecret);
      } else if (platform === 'facebook') {
        credentials = await socialMediaService.connectFacebook(accessToken);
      } else {
        return res.status(400).json({ message: "Unsupported platform" });
      }

      // Save credentials securely in database
      const socialAccountData = insertSocialAccountSchema.parse({
        userId,
        platform: credentials.platform,
        accountId: credentials.accountId,
        accountName: credentials.accountName,
        accessToken: credentials.accessToken,
        refreshToken: credentials.refreshToken,
        expiresAt: credentials.expiresAt,
        permissions: [],
        isActive: true,
        lastSyncAt: new Date()
      });

      await storage.createSocialAccount(socialAccountData);

      res.json({ success: true, platform: credentials.platform, accountName: credentials.accountName });
    } catch (error) {
      console.error("Social connection error:", error);
      res.status(500).json({ message: `Failed to connect ${req.params.platform}` });
    }
  });

  app.post('/api/social/post', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { platform, content, imageUrl, scheduledFor, socialAccountId } = req.body;

      // Get user's stored credentials for platform
      let socialAccount;
      if (socialAccountId) {
        socialAccount = await storage.getSocialAccount(socialAccountId);
      } else {
        // Find active account for this platform
        const accounts = await storage.getUserSocialAccounts(userId);
        socialAccount = accounts.find(acc => acc.platform === platform && acc.isActive);
      }

      if (!socialAccount) {
        return res.status(400).json({ message: `No connected ${platform} account found. Please connect your account first.` });
      }

      // Check if token is expired
      if (socialAccount.expiresAt && new Date() > socialAccount.expiresAt) {
        return res.status(400).json({ message: `${platform} account token has expired. Please reconnect your account.` });
      }

      const credentials = {
        platform: socialAccount.platform,
        accessToken: socialAccount.accessToken,
        refreshToken: socialAccount.refreshToken,
        accountId: socialAccount.accountId,
        accountName: socialAccount.accountName
      };

      let postId;
      const postData = { platform, content, imageUrl };

      if (platform === 'instagram') {
        postId = await socialMediaService.postToInstagram(credentials, postData);
      } else if (platform === 'linkedin') {
        postId = await socialMediaService.postToLinkedIn(credentials, postData);
      } else if (platform === 'twitter') {
        postId = await socialMediaService.postToTwitter(credentials, postData);
      } else if (platform === 'facebook') {
        postId = await socialMediaService.postToFacebook(credentials, postData);
      } else {
        return res.status(400).json({ message: "Unsupported platform" });
      }

      res.json({ success: true, postId, platform });
    } catch (error) {
      console.error("Social posting error:", error);
      res.status(500).json({ message: `Failed to post to ${req.body.platform}: ${error.message}` });
    }
  });

  // Publish scheduled content
  app.post('/api/content/:id/publish', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const contentId = parseInt(req.params.id);

      // Get the content to publish
      const content = await storage.getContentById(contentId);
      if (!content || content.userId !== userId) {
        return res.status(404).json({ message: "Content not found" });
      }

      if (content.status === 'published') {
        return res.status(400).json({ message: "Content is already published" });
      }

      // Get connected account for this platform
      const accounts = await storage.getUserSocialAccounts(userId);
      const socialAccount = accounts.find(acc => acc.platform === content.platform && acc.isActive);

      if (!socialAccount) {
        return res.status(400).json({ message: `No connected ${content.platform} account found. Please connect your account first.` });
      }

      // Check if token is expired
      if (socialAccount.expiresAt && new Date() > socialAccount.expiresAt) {
        return res.status(400).json({ message: `${content.platform} account token has expired. Please reconnect your account.` });
      }

      const credentials = {
        platform: socialAccount.platform,
        accessToken: socialAccount.accessToken,
        refreshToken: socialAccount.refreshToken,
        accountId: socialAccount.accountId,
        accountName: socialAccount.accountName
      };

      // Get media URLs if any
      let imageUrl;
      if (content.mediaIds && Array.isArray(content.mediaIds) && content.mediaIds.length > 0) {
        const media = await storage.getMediaById(content.mediaIds[0]);
        if (media) {
          imageUrl = media.url;
        }
      }

      // Post to platform
      let platformPostId;
      const postData = { 
        platform: content.platform, 
        content: content.body,
        imageUrl 
      };

      if (content.platform === 'instagram') {
        platformPostId = await socialMediaService.postToInstagram(credentials, postData);
      } else if (content.platform === 'linkedin') {
        platformPostId = await socialMediaService.postToLinkedIn(credentials, postData);
      } else if (content.platform === 'twitter') {
        platformPostId = await socialMediaService.postToTwitter(credentials, postData);
      } else if (content.platform === 'facebook') {
        platformPostId = await socialMediaService.postToFacebook(credentials, postData);
      } else {
        return res.status(400).json({ message: "Unsupported platform" });
      }

      // Update content status
      const updatedContent = await storage.updateContent(contentId, {
        status: 'published',
        publishedAt: new Date(),
        platformPostId,
        postStatus: 'posted'
      });

      res.json({ 
        success: true, 
        platformPostId, 
        content: updatedContent,
        message: `Successfully published to ${content.platform}` 
      });

    } catch (error) {
      console.error("Content publishing error:", error);
      res.status(500).json({ message: `Failed to publish content: ${error.message}` });
    }
  });

  // Lead scraping routes
  app.post('/api/leads/search', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { criteria } = req.body;
      const brandDna = await storage.getBrandDna(userId);

      if (!brandDna) {
        return res.status(400).json({ message: "Brand DNA required for lead search" });
      }

      const leads = await leadScrapingService.findLeads(criteria, brandDna);
      res.json(leads);
    } catch (error) {
      console.error("Lead search error:", error);
      res.status(500).json({ message: "Failed to search for leads" });
    }
  });

  // Email marketing routes
  app.post('/api/email/newsletter/generate', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const brandDna = await storage.getBrandDna(userId);
      const recentContent = await storage.getContent(userId, 10);

      if (!brandDna) {
        return res.status(400).json({ message: "Brand DNA required for newsletter generation" });
      }

      const newsletter = await emailMarketingService.generateNewsletterContent(brandDna, recentContent);
      res.json(newsletter);
    } catch (error) {
      console.error("Newsletter generation error:", error);
      res.status(500).json({ message: "Failed to generate newsletter" });
    }
  });

  app.post('/api/email/nurture/create', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const brandDna = await storage.getBrandDna(userId);

      if (!brandDna) {
        return res.status(400).json({ message: "Brand DNA required for nurture sequence" });
      }

      const sequence = await emailMarketingService.createNurtureSequence(brandDna);
      res.json(sequence);
    } catch (error) {
      console.error("Nurture sequence creation error:", error);
      res.status(500).json({ message: "Failed to create nurture sequence" });
    }
  });

  // Object storage routes for media library
  // Endpoint for serving private objects with ACL protection
  app.get("/objects/:objectPath(*)", isAuthenticated, async (req: any, res) => {
    const userId = req.user?.claims?.sub;
    const objectStorageService = new ObjectStorageService();
    try {
      const objectFile = await objectStorageService.getObjectEntityFile(
        req.path,
      );
      const canAccess = await objectStorageService.canAccessObjectEntity({
        objectFile,
        userId: userId,
        requestedPermission: ObjectPermission.READ,
      });
      if (!canAccess) {
        return res.sendStatus(401);
      }
      objectStorageService.downloadObject(objectFile, res);
    } catch (error) {
      console.error("Error checking object access:", error);
      if (error instanceof ObjectNotFoundError) {
        return res.sendStatus(404);
      }
      return res.sendStatus(500);
    }
  });

  // Endpoint for getting upload URL for media files
  app.post("/api/objects/upload", isAuthenticated, async (req: any, res) => {
    try {
      // Validate object storage configuration first
      if (!process.env.PRIVATE_OBJECT_DIR) {
        return res.status(500).json({ 
          error: "Object storage not configured", 
          details: "PRIVATE_OBJECT_DIR environment variable is not set" 
        });
      }

      const objectStorageService = new ObjectStorageService();
      const uploadURL = await objectStorageService.getObjectEntityUploadURL();
      res.json({ uploadURL });
    } catch (error) {
      console.error("Error generating upload URL:", error);
      if (error instanceof Error && error.message.includes('PRIVATE_OBJECT_DIR not set')) {
        return res.status(500).json({ 
          error: "Object storage not configured", 
          details: "Please set up object storage in the Object Storage tool" 
        });
      }
      res.status(500).json({ error: "Failed to generate upload URL" });
    }
  });

  // Endpoint for updating media library after file upload
  app.put("/api/media-library", isAuthenticated, async (req: any, res) => {
    try {
      const { fileUrl, fileName, fileType, fileSize } = req.body;

      if (!fileUrl || !fileName) {
        return res.status(400).json({ error: "fileUrl and fileName are required" });
      }

      const userId = req.user.claims.sub;
      const objectStorageService = new ObjectStorageService();

      // CRITICAL: Normalize the uploaded URL and set ACL policy for secure access
      const normalizedPath = await objectStorageService.trySetObjectEntityAclPolicy(
        fileUrl,
        {
          owner: userId,
          visibility: "private", // Media files are private to the user
        },
      );

      // Save media metadata to database with normalized secure path
      const mediaData = insertMediaLibrarySchema.parse({
        userId,
        fileName,
        fileType,
        fileSize: fileSize || 0,
        url: normalizedPath, // Use normalized path, not raw signed URL
      });

      const media = await storage.createMediaLibrary(mediaData);
      res.json(media);
    } catch (error) {
      console.error("Error saving media file:", error);
      if (error instanceof Error && error.name === 'ZodError') {
        return res.status(400).json({ message: "Invalid request data", errors: (error as any).errors });
      }
      res.status(500).json({ error: "Failed to save media file" });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

server/storage.ts.content:
import {
  users,
  brandDna,
  tasks,
  content,
  leads,
  outreachMessages,
  metrics,
  strategyReports,
  savedArticles,
  socialAccounts,
  mediaLibrary,
  type User,
  type UpsertUser,
  type BrandDna,
  type InsertBrandDna,
  type Task,
  type InsertTask,
  type Content,
  type InsertContent,
  type Lead,
  type InsertLead,
  type OutreachMessage,
  type InsertOutreachMessage,
  type Metrics,
  type InsertMetrics,
  type StrategyReport,
  type InsertStrategyReport,
  type SavedArticle,
  type InsertSavedArticle,
  type SocialAccount,
  type InsertSocialAccount,
  type SafeSocialAccount,
  type MediaLibrary,
  type InsertMediaLibrary,
} from "@shared/schema";
import { db } from "./db";
import { eq, and, desc, gte, lte } from "drizzle-orm";

// Interface for storage operations
export interface IStorage {
  // User operations (IMPORTANT: mandatory for Replit Auth)
  getUser(id: string): Promise<User | undefined>;
  upsertUser(user: UpsertUser): Promise<User>;

  // Brand DNA operations
  getBrandDna(userId: string): Promise<BrandDna | undefined>;
  upsertBrandDna(brandDnaData: InsertBrandDna): Promise<BrandDna>;

  // Task operations
  getTasks(userId: string, dueDate?: Date): Promise<Task[]>;
  createTask(task: InsertTask): Promise<Task>;
  updateTask(id: number, updates: Partial<Task>): Promise<Task>;
  completeTask(id: number): Promise<Task>;

  // Content operations
  getContent(userId: string, limit?: number): Promise<Content[]>;
  createContent(content: InsertContent): Promise<Content>;
  updateContent(id: number, updates: Partial<Content>): Promise<Content>;
  deleteContent(id: number): Promise<void>;
  getContentByStatus(userId: string, status: string): Promise<Content[]>;

  // Lead operations
  getLeads(userId: string): Promise<Lead[]>;
  createLead(lead: InsertLead): Promise<Lead>;
  updateLead(id: number, userId: string, updates: Partial<Lead>): Promise<Lead | null>;
  getLeadsByStatus(userId: string, status: string): Promise<Lead[]>;

  // Outreach operations
  getOutreachMessages(userId: string, leadId?: number): Promise<OutreachMessage[]>;
  createOutreachMessage(message: InsertOutreachMessage): Promise<OutreachMessage>;
  updateOutreachMessage(id: number, updates: Partial<OutreachMessage>): Promise<OutreachMessage>;

  // Metrics operations
  getMetrics(userId: string, week?: string): Promise<Metrics | undefined>;
  upsertMetrics(metricsData: InsertMetrics): Promise<Metrics>;

  // Strategy operations
  getStrategyReport(userId: string, week?: string): Promise<StrategyReport | undefined>;
  createStrategyReport(report: InsertStrategyReport): Promise<StrategyReport>;

  // Saved articles operations (Reading Hub)
  getSavedArticles(userId: string, category?: string): Promise<SavedArticle[]>;
  createSavedArticle(article: InsertSavedArticle): Promise<SavedArticle>;
  updateSavedArticle(id: number, userId: string, updates: Partial<SavedArticle>): Promise<SavedArticle | null>;
  deleteSavedArticle(id: number, userId: string): Promise<boolean>;
  getSavedArticleById(id: number, userId: string): Promise<SavedArticle | undefined>;
  markArticleAsRead(id: number, userId: string, isRead: boolean): Promise<SavedArticle | null>;
  toggleArticleFavorite(id: number, userId: string, isFavorite: boolean): Promise<SavedArticle | null>;

  // Social account operations
  getSocialAccounts(userId: string): Promise<SocialAccount[]>;
  getSafeSocialAccounts(userId: string): Promise<SafeSocialAccount[]>;
  createSocialAccount(account: InsertSocialAccount): Promise<SocialAccount>;
  createSafeSocialAccount(account: InsertSocialAccount): Promise<SafeSocialAccount>;
  updateSocialAccount(id: number, userId: string, updates: Partial<SocialAccount>): Promise<SocialAccount | null>;
  updateSafeSocialAccount(id: number, userId: string, updates: Partial<SocialAccount>): Promise<SafeSocialAccount | null>;
  deleteSocialAccount(id: number, userId: string): Promise<boolean>;
  getSocialAccountById(id: number, userId: string): Promise<SocialAccount | undefined>;
  getSafeSocialAccountById(id: number, userId: string): Promise<SafeSocialAccount | undefined>;
  getSocialAccountByPlatform(userId: string, platform: string): Promise<SocialAccount | undefined>;

  // Media library operations
  getMediaLibrary(userId: string): Promise<MediaLibrary[]>;
  createMediaItem(media: InsertMediaLibrary): Promise<MediaLibrary>;
  updateMediaItem(id: number, userId: string, updates: Partial<MediaLibrary>): Promise<MediaLibrary | null>;
  deleteMediaItem(id: number, userId: string): Promise<boolean>;
  getMediaItemById(id: number, userId: string): Promise<MediaLibrary | undefined>;
}

export class DatabaseStorage implements IStorage {
  // User operations (IMPORTANT: mandatory for Replit Auth)
  async getUser(id: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.id, id));
    return user;
  }

  async upsertUser(userData: UpsertUser): Promise<User> {
    const [user] = await db
      .insert(users)
      .values(userData)
      .onConflictDoUpdate({
        target: users.id,
        set: {
          ...userData,
          updatedAt: new Date(),
        },
      })
      .returning();
    return user;
  }

  // Brand DNA operations
  async getBrandDna(userId: string): Promise<BrandDna | undefined> {
    const [dna] = await db.select().from(brandDna).where(eq(brandDna.userId, userId));
    return dna;
  }

  async upsertBrandDna(brandDnaData: InsertBrandDna): Promise<BrandDna> {
    const [dna] = await db
      .insert(brandDna)
      .values(brandDnaData)
      .onConflictDoUpdate({
        target: brandDna.userId,
        set: {
          ...brandDnaData,
          updatedAt: new Date(),
        },
      })
      .returning();
    return dna;
  }

  // Task operations
  async getTasks(userId: string, dueDate?: Date): Promise<Task[]> {
    if (dueDate) {
      const startOfDay = new Date(dueDate);
      startOfDay.setHours(0, 0, 0, 0);
      const endOfDay = new Date(dueDate);
      endOfDay.setHours(23, 59, 59, 999);

      return await db.select().from(tasks).where(
        and(
          eq(tasks.userId, userId),
          gte(tasks.dueDate, startOfDay),
          lte(tasks.dueDate, endOfDay)
        )
      ).orderBy(desc(tasks.priority), tasks.createdAt);
    }

    return await db.select().from(tasks).where(eq(tasks.userId, userId)).orderBy(desc(tasks.priority), tasks.createdAt);
  }

  async createTask(task: InsertTask): Promise<Task> {
    const [newTask] = await db.insert(tasks).values(task).returning();
    return newTask;
  }

  async updateTask(id: number, updates: Partial<Task>): Promise<Task> {
    const [updatedTask] = await db
      .update(tasks)
      .set(updates)
      .where(eq(tasks.id, id))
      .returning();
    return updatedTask;
  }

  async completeTask(id: number): Promise<Task> {
    const [completedTask] = await db
      .update(tasks)
      .set({ completed: true, completedAt: new Date() })
      .where(eq(tasks.id, id))
      .returning();
    return completedTask;
  }

  // Content operations
  async getContent(userId: string, limit = 50): Promise<Content[]> {
    return await db
      .select()
      .from(content)
      .where(eq(content.userId, userId))
      .orderBy(desc(content.createdAt))
      .limit(limit);
  }

  async createContent(contentData: InsertContent): Promise<Content> {
    const [newContent] = await db.insert(content).values(contentData).returning();
    return newContent;
  }

  async updateContent(id: number, updates: Partial<Content>): Promise<Content> {
    const [updatedContent] = await db
      .update(content)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(content.id, id))
      .returning();
    return updatedContent;
  }

  async getContentByStatus(userId: string, status: string): Promise<Content[]> {
    return await db
      .select()
      .from(content)
      .where(and(eq(content.userId, userId), eq(content.status, status)))
      .orderBy(desc(content.createdAt));
  }

  async deleteContent(id: number): Promise<void> {
    await db.delete(content).where(eq(content.id, id));
  }

  // Lead operations
  async getLeads(userId: string): Promise<Lead[]> {
    return await db
      .select()
      .from(leads)
      .where(eq(leads.userId, userId))
      .orderBy(desc(leads.updatedAt));
  }

  async createLead(leadData: InsertLead): Promise<Lead> {
    const [newLead] = await db.insert(leads).values(leadData).returning();
    return newLead;
  }

  async updateLead(id: number, userId: string, updates: Partial<Lead>): Promise<Lead | null> {
    const [updatedLead] = await db
      .update(leads)
      .set({ ...updates, updatedAt: new Date() })
      .where(and(eq(leads.id, id), eq(leads.userId, userId)))
      .returning();
    return updatedLead || null;
  }

  async getLeadsByStatus(userId: string, status: string): Promise<Lead[]> {
    return await db
      .select()
      .from(leads)
      .where(and(eq(leads.userId, userId), eq(leads.status, status)))
      .orderBy(desc(leads.updatedAt));
  }

  // Outreach operations
  async getOutreachMessages(userId: string, leadId?: number): Promise<OutreachMessage[]> {
    if (leadId) {
      return await db.select().from(outreachMessages).where(
        and(
          eq(outreachMessages.userId, userId),
          eq(outreachMessages.leadId, leadId)
        )
      ).orderBy(desc(outreachMessages.createdAt));
    }

    return await db.select().from(outreachMessages).where(eq(outreachMessages.userId, userId)).orderBy(desc(outreachMessages.createdAt));
  }

  async createOutreachMessage(message: InsertOutreachMessage): Promise<OutreachMessage> {
    const [newMessage] = await db.insert(outreachMessages).values(message).returning();
    return newMessage;
  }

  async updateOutreachMessage(id: number, updates: Partial<OutreachMessage>): Promise<OutreachMessage> {
    const [updatedMessage] = await db
      .update(outreachMessages)
      .set(updates)
      .where(eq(outreachMessages.id, id))
      .returning();
    return updatedMessage;
  }

  // Metrics operations
  async getMetrics(userId: string, week?: string): Promise<Metrics | undefined> {
    if (week) {
      const [metricsData] = await db.select().from(metrics).where(
        and(
          eq(metrics.userId, userId),
          eq(metrics.week, week)
        )
      ).orderBy(desc(metrics.createdAt));
      return metricsData;
    }

    const [metricsData] = await db.select().from(metrics).where(eq(metrics.userId, userId)).orderBy(desc(metrics.createdAt));
    return metricsData;
  }

  async upsertMetrics(metricsData: InsertMetrics): Promise<Metrics> {
    const [metric] = await db
      .insert(metrics)
      .values(metricsData)
      .onConflictDoUpdate({
        target: [metrics.userId, metrics.week],
        set: {
          ...metricsData,
          createdAt: new Date(),
        },
      })
      .returning();
    return metric;
  }

  // Strategy operations
  async getStrategyReport(userId: string, week?: string): Promise<StrategyReport | undefined> {
    if (week) {
      const [report] = await db.select().from(strategyReports).where(
        and(
          eq(strategyReports.userId, userId),
          eq(strategyReports.week, week)
        )
      ).orderBy(desc(strategyReports.createdAt));
      return report;
    }

    const [report] = await db.select().from(strategyReports).where(eq(strategyReports.userId, userId)).orderBy(desc(strategyReports.createdAt));
    return report;
  }

  async createStrategyReport(report: InsertStrategyReport): Promise<StrategyReport> {
    const [newReport] = await db.insert(strategyReports).values(report).returning();
    return newReport;
  }

  // Saved articles operations (Reading Hub)
  async getSavedArticles(userId: string, category?: string): Promise<SavedArticle[]> {
    const conditions = [eq(savedArticles.userId, userId)];

    if (category && category !== 'all') {
      conditions.push(eq(savedArticles.category, category));
    }

    return await db.select()
      .from(savedArticles)
      .where(and(...conditions))
      .orderBy(desc(savedArticles.createdAt));
  }

  async createSavedArticle(article: InsertSavedArticle): Promise<SavedArticle> {
    const [newArticle] = await db.insert(savedArticles).values(article).returning();
    return newArticle;
  }

  async updateSavedArticle(id: number, userId: string, updates: Partial<SavedArticle>): Promise<SavedArticle | null> {
    const [updatedArticle] = await db.update(savedArticles)
      .set({ ...updates, updatedAt: new Date() })
      .where(and(eq(savedArticles.id, id), eq(savedArticles.userId, userId)))
      .returning();
    return updatedArticle || null;
  }

  async deleteSavedArticle(id: number, userId: string): Promise<boolean> {
    const result = await db.delete(savedArticles)
      .where(and(eq(savedArticles.id, id), eq(savedArticles.userId, userId)));
    return (result.rowCount ?? 0) > 0;
  }

  async getSavedArticleById(id: number, userId: string): Promise<SavedArticle | undefined> {
    const [article] = await db.select().from(savedArticles)
      .where(and(eq(savedArticles.id, id), eq(savedArticles.userId, userId)));
    return article;
  }

  async markArticleAsRead(id: number, userId: string, isRead: boolean): Promise<SavedArticle | null> {
    const [updatedArticle] = await db.update(savedArticles)
      .set({ isRead, updatedAt: new Date() })
      .where(and(eq(savedArticles.id, id), eq(savedArticles.userId, userId)))
      .returning();
    return updatedArticle || null;
  }

  async toggleArticleFavorite(id: number, userId: string, isFavorite: boolean): Promise<SavedArticle | null> {
    const [updatedArticle] = await db.update(savedArticles)
      .set({ isFavorite, updatedAt: new Date() })
      .where(and(eq(savedArticles.id, id), eq(savedArticles.userId, userId)))
      .returning();
    return updatedArticle || null;
  }

  // Social account operations
  async getSocialAccounts(userId: string): Promise<SocialAccount[]> {
    return await db.select()
      .from(socialAccounts)
      .where(eq(socialAccounts.userId, userId))
      .orderBy(desc(socialAccounts.createdAt));
  }

  async createSocialAccount(account: InsertSocialAccount): Promise<SocialAccount> {
    const [newAccount] = await db.insert(socialAccounts).values(account).returning();
    return newAccount;
  }

  async updateSocialAccount(id: number, userId: string, updates: Partial<SocialAccount>): Promise<SocialAccount | null> {
    const [updatedAccount] = await db.update(socialAccounts)
      .set({ ...updates, updatedAt: new Date() })
      .where(and(eq(socialAccounts.id, id), eq(socialAccounts.userId, userId)))
      .returning();
    return updatedAccount || null;
  }

  async deleteSocialAccount(id: number, userId: string): Promise<boolean> {
    const result = await db.delete(socialAccounts)
      .where(and(eq(socialAccounts.id, id), eq(socialAccounts.userId, userId)));
    return (result.rowCount ?? 0) > 0;
  }

  async getSocialAccountById(id: number, userId: string): Promise<SocialAccount | undefined> {
    const [account] = await db.select().from(socialAccounts)
      .where(and(eq(socialAccounts.id, id), eq(socialAccounts.userId, userId)));
    return account;
  }

  async getSocialAccountByPlatform(userId: string, platform: string): Promise<SocialAccount | undefined> {
    const [account] = await db.select().from(socialAccounts)
      .where(and(eq(socialAccounts.userId, userId), eq(socialAccounts.platform, platform)));
    return account;
  }

  // Helper function to create safe social account (excludes sensitive fields)
  private toSafeSocialAccount(account: SocialAccount): SafeSocialAccount {
    const { accessToken, refreshToken, ...safeAccount } = account;
    return safeAccount;
  }

  // Safe social account operations for API responses
  async getSafeSocialAccounts(userId: string): Promise<SafeSocialAccount[]> {
    const accounts = await this.getSocialAccounts(userId);
    return accounts.map(account => this.toSafeSocialAccount(account));
  }

  async createSafeSocialAccount(account: InsertSocialAccount): Promise<SafeSocialAccount> {
    const newAccount = await this.createSocialAccount(account);
    return this.toSafeSocialAccount(newAccount);
  }

  async updateSafeSocialAccount(id: number, userId: string, updates: Partial<SocialAccount>): Promise<SafeSocialAccount | null> {
    const updatedAccount = await this.updateSocialAccount(id, userId, updates);
    return updatedAccount ? this.toSafeSocialAccount(updatedAccount) : null;
  }

  async getSafeSocialAccountById(id: number, userId: string): Promise<SafeSocialAccount | undefined> {
    const account = await this.getSocialAccountById(id, userId);
    return account ? this.toSafeSocialAccount(account) : undefined;
  }

  // Media library operations
  async getMediaLibrary(userId: string): Promise<MediaLibrary[]> {
    return await db.select()
      .from(mediaLibrary)
      .where(eq(mediaLibrary.userId, userId))
      .orderBy(desc(mediaLibrary.createdAt));
  }

  async createMediaItem(media: InsertMediaLibrary): Promise<MediaLibrary> {
    const [newMedia] = await db.insert(mediaLibrary).values(media).returning();
    return newMedia;
  }

  async updateMediaItem(id: number, userId: string, updates: Partial<MediaLibrary>): Promise<MediaLibrary | null> {
    const [updatedMedia] = await db.update(mediaLibrary)
      .set({ ...updates, updatedAt: new Date() })
      .where(and(eq(mediaLibrary.id, id), eq(mediaLibrary.userId, userId)))
      .returning();
    return updatedMedia || null;
  }

  async deleteMediaItem(id: number, userId: string): Promise<boolean> {
    const result = await db.delete(mediaLibrary)
      .where(and(eq(mediaLibrary.id, id), eq(mediaLibrary.userId, userId)));
    return (result.rowCount ?? 0) > 0;
  }

  async getMediaItemById(id: number, userId: string): Promise<MediaLibrary | undefined> {
    const [media] = await db.select().from(mediaLibrary)
      .where(and(eq(mediaLibrary.id, id), eq(mediaLibrary.userId, userId)));
    return media;
  }
}

export const storage = new DatabaseStorage();

