client/src/components/todays-tasks.tsx.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Checkbox } from "@/components/ui/checkbox";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { Loader2, Plus } from "lucide-react";

interface Task {
  id: number;
  title: string;
  description: string;
  type: string;
  category: string;
  priority: number;
  completed: boolean;
  completedAt?: string;
  dueDate?: string;
}

export default function TodaysTasks() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isGenerating, setIsGenerating] = useState(false);

  const today = new Date().toISOString().split('T')[0];

  const { data: tasks = [], isLoading } = useQuery({
    queryKey: ['/api/tasks', { date: today }],
    retry: false,
  });

  const completeTaskMutation = useMutation({
    mutationFn: async (taskId: number) => {
      await apiRequest("POST", `/api/tasks/${taskId}/complete`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/tasks'] });
      toast({
        title: "Task completed!",
        description: "Great job staying on track.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to complete task. Please try again.",
        variant: "destructive",
      });
    },
  });

  const generateTasksMutation = useMutation({
    mutationFn: async () => {
      setIsGenerating(true);
      await apiRequest("POST", "/api/tasks/generate-daily");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/tasks'] });
      toast({
        title: "New tasks generated!",
        description: "Your AI co-pilot has created today's strategic tasks.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      let errorMessage = "Failed to generate tasks. Please try again.";
      if (error.message.includes("429") || error.message.includes("quota")) {
        errorMessage = "AI service temporarily unavailable. Your strategic framework is saved and will generate personalized tasks once service resumes.";
      }

      toast({
        title: "Tasks Generation",
        description: errorMessage,
        variant: "destructive",
      });
    },
    onSettled: () => {
      setIsGenerating(false);
    },
  });

  const handleTaskComplete = (taskId: number, completed: boolean) => {
    if (!completed) {
      completeTaskMutation.mutate(taskId);
    }
  };

  const completedTasks = tasks.filter((task: Task) => task.completed);
  const pendingTasks = tasks.filter((task: Task) => !task.completed);

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'trust':
        return 'bg-secondary/10 text-secondary';
      case 'conversion':
        return 'bg-accent/10 text-accent';
      case 'engagement':
        return 'bg-info/10 text-info';
      case 'visibility':
        return 'bg-primary/10 text-primary';
      default:
        return 'bg-slate-100 text-slate-600';
    }
  };

  if (isLoading) {
    return (
      <div className="bg-white rounded-xl shadow-sm border border-slate-200">
        <div className="p-6 border-b border-slate-200">
          <h2 className="text-lg font-semibold text-slate-900">Today's Tasks</h2>
        </div>
        <div className="p-6 flex items-center justify-center">
          <Loader2 className="w-6 h-6 animate-spin text-slate-400" />
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200">
      <div className="p-6 border-b border-slate-200">
        <div className="flex items-center justify-between">
          <h2 className="text-lg font-semibold text-slate-900">Today's Tasks</h2>
          <div className="flex items-center space-x-3">
            <span className="text-sm text-slate-500">
              {completedTasks.length} of {tasks.length} completed
            </span>
            <Button 
              size="sm" 
              onClick={() => generateTasksMutation.mutate()}
              disabled={isGenerating}
              className="flex items-center space-x-2"
            >
              {isGenerating ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Plus className="w-4 h-4" />
              )}
              <span>{isGenerating ? "Generating..." : "Generate Tasks"}</span>
            </Button>
          </div>
        </div>
      </div>

      <div className="p-6 space-y-4">
        {tasks.length === 0 ? (
          <div className="text-center py-8">
            <p className="text-slate-500 mb-4">No tasks for today yet.</p>
            <Button onClick={() => generateTasksMutation.mutate()} disabled={isGenerating}>
              {isGenerating ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin mr-2" />
                  Generating...
                </>
              ) : (
                "Generate Today's Tasks"
              )}
            </Button>
          </div>
        ) : (
          <>
            {/* Completed Tasks */}
            {completedTasks.map((task: Task) => (
              <div 
                key={task.id} 
                className="flex items-start space-x-3 p-4 bg-secondary/5 rounded-lg border border-secondary/20"
              >
                <Checkbox 
                  checked={true}
                  disabled
                  className="mt-1"
                />
                <div className="flex-1">
                  <h3 className="font-medium text-slate-900 line-through">{task.title}</h3>
                  <p className="text-sm text-slate-600 mt-1">{task.description}</p>
                  <div className="flex items-center space-x-2 mt-2">
                    <Badge className={getCategoryColor(task.category)}>
                      {task.category.charAt(0).toUpperCase() + task.category.slice(1)}
                    </Badge>
                    <span className="text-xs text-slate-500">
                      ✅ Completed {task.completedAt ? new Date(task.completedAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : 'recently'}
                    </span>
                  </div>
                </div>
              </div>
            ))}

            {/* Pending Tasks */}
            {pendingTasks.map((task: Task) => (
              <div 
                key={task.id} 
                className="flex items-start space-x-3 p-4 border-2 border-dashed border-slate-200 rounded-lg hover:border-primary/50 transition-colors"
              >
                <Checkbox 
                  checked={false}
                  onCheckedChange={() => handleTaskComplete(task.id, task.completed)}
                  className="mt-1"
                />
                <div className="flex-1">
                  <h3 className="font-medium text-slate-900">{task.title}</h3>
                  <p className="text-sm text-slate-600 mt-1">{task.description}</p>
                  <div className="flex items-center space-x-2 mt-2">
                    <Badge className={getCategoryColor(task.category)}>
                      {task.category.charAt(0).toUpperCase() + task.category.slice(1)}
                    </Badge>
                  </div>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
}

