  resource: Content;
}

interface PostFormData {
  title: string;
  body: string;
  platform: string;
  contentType: string;
  pillar: string;
  goal: string;
  scheduledFor?: Date;
}

const PLATFORMS = [
  { value: 'instagram', label: 'Instagram', color: 'bg-gradient-to-r from-purple-500 to-pink-500', charLimit: 2200 },
  { value: 'linkedin', label: 'LinkedIn', color: 'bg-blue-600', charLimit: 3000 },
