  { value: 'facebook', label: 'Facebook', color: 'bg-blue-700', charLimit: 63206 },
  { value: 'email', label: 'Email', color: 'bg-green-600', charLimit: 10000 },
  { value: 'blog', label: 'Blog', color: 'bg-gray-700', charLimit: 50000 },
];

const CONTENT_TYPES = [
  { value: 'post', label: 'Social Post' },
  { value: 'story', label: 'Story' },
  { value: 'email', label: 'Email' },
  { value: 'article', label: 'Article' },
];

const GOALS = [
  { value: 'visibility', label: 'Visibility' },
  { value: 'trust', label: 'Trust Building' },
  { value: 'conversion', label: 'Conversion' },
  { value: 'engagement', label: 'Engagement' },
];

const STATUS_FILTERS = [
  { value: 'all', label: 'All Posts' },
  { value: 'draft', label: 'Drafts' },
  { value: 'scheduled', label: 'Scheduled' },
  { value: 'published', label: 'Published' },
];

const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

interface ContentCalendarProps {
  onSearchClick?: () => void;
}

export default function ContentCalendar({ onSearchClick }: ContentCalendarProps) {
  const [view, setView] = useState<'calendar' | 'list' | 'accounts' | 'media'>('calendar');
  const [statusFilter, setStatusFilter] = useState('all');
  const [platformFilter, setPlatformFilter] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [selectedPost, setSelectedPost] = useState<Content | null>(null);
  const [formData, setFormData] = useState<PostFormData>({
    title: '',
    body: '',
    platform: 'instagram',
    contentType: 'post',
    pillar: '',
    goal: 'engagement',
  });

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch content
  const { data: content = [], isLoading } = useQuery({
    queryKey: ['/api/content'],
    queryFn: () => fetch('/api/content').then(res => res.json()),
  });

  // Create content mutation
  const createContentMutation = useMutation({
    mutationFn: (data: PostFormData) => 
      fetch('/api/content', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/content'] });
      setShowCreateDialog(false);
      resetForm();
      toast({ title: 'Content created successfully!' });
    },
    onError: () => {
      toast({ title: 'Failed to create content', variant: 'destructive' });
    },
  });

  // Update content mutation
  const updateContentMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: Partial<Content> }) => 
      fetch(`/api/content/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/content'] });
      toast({ title: 'Content updated successfully!' });
    },
  });

  // Delete content mutation
  const deleteContentMutation = useMutation({
    mutationFn: (id: number) => 
      fetch(`/api/content/${id}`, { method: 'DELETE' }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/content'] });
      toast({ title: 'Content deleted successfully!' });
    },
  });

  // Fetch social accounts
  const { data: socialAccounts = [], isLoading: accountsLoading } = useQuery({
    queryKey: ['/api/social-accounts'],
    queryFn: () => fetch('/api/social-accounts').then(res => res.json()),
  });

  // Connect social account mutation
  const connectAccountMutation = useMutation({
    mutationFn: (data: { platform: string; accessToken: string; accountId: string; accountName: string }) => 
      fetch('/api/social-accounts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/social-accounts'] });
      toast({ title: 'Account connected successfully!' });
    },
    onError: () => {
      toast({ title: 'Failed to connect account', variant: 'destructive' });
    },
  });

  // Disconnect social account mutation
  const disconnectAccountMutation = useMutation({
    mutationFn: (id: number) => 
      fetch(`/api/social-accounts/${id}`, { method: 'DELETE' }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/social-accounts'] });
      toast({ title: 'Account disconnected successfully!' });
    },
  });

  // Fetch media library
  const { data: mediaLibrary = [], isLoading: mediaLoading } = useQuery({
    queryKey: ['/api/media-library'],
    queryFn: () => fetch('/api/media-library').then(res => res.json()),
  });

  // Media upload mutation
  const uploadMediaMutation = useMutation({
    mutationFn: async (data: { fileUrl: string; fileName: string; fileType: string; fileSize: number }) => 
      fetch('/api/media-library', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/media-library'] });
      toast({ title: 'Media uploaded successfully!' });
    },
    onError: () => {
      toast({ title: 'Failed to upload media', variant: 'destructive' });
    },
  });

  // Delete media mutation
  const deleteMediaMutation = useMutation({
    mutationFn: (id: number) => 
      fetch(`/api/media-library/${id}`, { method: 'DELETE' }).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/media-library'] });
      toast({ title: 'Media deleted successfully!' });
    },
  });

  // AI content generation mutation
  const generateContentMutation = useMutation({
    mutationFn: (params: { platform: string; goal: string; pillar: string; topic: string }) => 
      fetch('/api/content/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(params),
      }).then(res => res.json()),
    onSuccess: (data) => {
      setFormData(prev => ({
        ...prev,
        title: data.title,
        body: data.content,
        pillar: data.pillar,
      }));
      toast({ title: 'AI content generated successfully!' });
    },
  });

  // Publish content mutation
  const publishContentMutation = useMutation({
    mutationFn: (contentId: number) => 
      fetch(`/api/content/${contentId}/publish`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      }).then(res => res.json()),
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['/api/content'] });
      toast({ 
        title: 'Content published successfully!',
        description: `Posted to ${data.platform}` 
      });
    },
    onError: (error: any) => {
      toast({ 
        title: 'Failed to publish content', 
        description: error.message || 'Please check your account connection',
        variant: 'destructive' 
      });
    },
  });

  // Filter content based on status, platform, and search
  const filteredContent = content.filter((item: Content) => {
    if (statusFilter !== 'all' && item.status !== statusFilter) return false;
    if (platformFilter !== 'all' && item.platform !== platformFilter) return false;
    if (searchQuery && !item.title.toLowerCase().includes(searchQuery.toLowerCase()) && 
        !item.body.toLowerCase().includes(searchQuery.toLowerCase())) return false;
    return true;
  });

  // Convert content to calendar events
  const events: ContentEvent[] = filteredContent
    .filter((item: Content) => item.scheduledFor)
    .map((item: Content) => ({
      id: item.id,
      title: item.title,
      start: new Date(item.scheduledFor!),
      end: new Date(new Date(item.scheduledFor!).getTime() + 60 * 60 * 1000), // 1 hour duration
      resource: item,
    }));

  const resetForm = () => {
    setFormData({
      title: '',
      body: '',
      platform: 'instagram',
      contentType: 'post',
      pillar: '',
      goal: 'engagement',
    });
    setSelectedPost(null);
  };

  const handleCreatePost = () => {
    createContentMutation.mutate(formData);
  };

  const handleCreateAndPublish = async () => {
    // First create the content, then publish it
    try {
      const response = await fetch('/api/content', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        throw new Error('Failed to create content');
      }

      const createdContent = await response.json();

      // Now publish the created content
      publishContentMutation.mutate(createdContent.id);

      // Clean up
      queryClient.invalidateQueries({ queryKey: ['/api/content'] });
      setShowCreateDialog(false);
      resetForm();

    } catch (error) {
      toast({ 
        title: 'Failed to create and publish content', 
        variant: 'destructive' 
      });
    }
  };

  const handleUpdatePost = (id: number, updates: Partial<Content>) => {
    updateContentMutation.mutate({ id, data: updates });
  };

  const handleDeletePost = (id: number) => {
    deleteContentMutation.mutate(id);
  };

  const handleSelectEvent = (event: ContentEvent) => {
    setSelectedPost(event.resource);
    setFormData({
      title: event.resource.title,
      body: event.resource.body,
      platform: event.resource.platform,
      contentType: event.resource.contentType,
      pillar: event.resource.pillar,
      goal: event.resource.goal,
      scheduledFor: event.resource.scheduledFor ? new Date(event.resource.scheduledFor) : undefined,
    });
    setShowCreateDialog(true);
  };

  const handleConnectAccount = (platform: string) => {
    // For now, we'll simulate the OAuth process with a mock connection
    // In a real implementation, this would redirect to the OAuth provider
    const mockAccessToken = `mock_token_${Date.now()}`;
    const mockAccountId = `mock_id_${Date.now()}`;
    const mockAccountName = `Test ${platform} Account`;

    connectAccountMutation.mutate({
      platform,
      accessToken: mockAccessToken,
      accountId: mockAccountId,
      accountName: mockAccountName,
    });

    toast({
      title: `Connecting to ${platform}...`,
      description: "This is a demo connection. In production, you'll be redirected to OAuth.",
    });
  };

  const handleGenerateContent = () => {
    if (!formData.platform || !formData.goal || !formData.pillar) {
      toast({ title: 'Please fill in platform, goal, and pillar first', variant: 'destructive' });
      return;
    }

    generateContentMutation.mutate({
      platform: formData.platform,
      goal: formData.goal,
      pillar: formData.pillar,
      topic: formData.title || 'general business topic',
    });
  };

  // Handle media upload
  const handleGetUploadParameters = async () => {
    try {
      const response = await fetch('/api/objects/upload', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });
      const data = await response.json();
      return {
        method: 'PUT' as const,
        url: data.uploadURL,
      };
    } catch (error) {
      console.error('Error getting upload parameters:', error);
      toast({ title: 'Failed to get upload URL', variant: 'destructive' });
      throw error;
    }
  };

  const handleUploadComplete = (result: any) => {
    if (result.successful && result.successful.length > 0) {
      const file = result.successful[0];
      const fileUrl = file.uploadURL;
      const fileName = file.name || 'Uploaded file';
      const fileType = file.type || 'unknown';
      const fileSize = file.size || 0;

      uploadMediaMutation.mutate({
        fileUrl,
        fileName,
        fileType,
        fileSize,
      });
    }
  };

  const handleDeleteMedia = (id: number) => {
    if (confirm('Are you sure you want to delete this media file?')) {
      deleteMediaMutation.mutate(id);
    }
  };

  // Drag-and-drop event handlers
  const handleEventDrop = ({ event, start, end }: any) => {
    const updatedContent = {
      scheduledFor: start,
    };

    handleUpdatePost(event.id, updatedContent);
    toast({ 
      title: 'Event moved successfully', 
      description: `Rescheduled to ${format(start, 'MMM d, h:mm a')}` 
    });
  };

  const handleEventResize = ({ event, start, end }: any) => {
    const updatedContent = {
      scheduledFor: start,
    };

    handleUpdatePost(event.id, updatedContent);
    toast({ 
      title: 'Event updated successfully', 
      description: `Rescheduled to ${format(start, 'MMM d, h:mm a')}` 
