                                </Button>
                              </div>
                            ) : (
                              <div className="space-y-3">
                                <div className="p-3 bg-slate-50 rounded-lg border border-slate-200">
                                  <p className="text-slate-600 text-sm">
                                    Connect your {platform.label} account to enable content posting and scheduling.
                                  </p>
                                </div>
                                <Button
                                  size="sm"
                                  onClick={() => handleConnectAccount(platform.value)}
                                  disabled={isConnecting}
                                  className="w-full"
                                  data-testid={`connect-${platform.value}`}
                                >
                                  {isConnecting ? 'Connecting...' : `Connect ${platform.label}`}
                                  <ExternalLink className="h-4 w-4 ml-2" />
                                </Button>
                              </div>
                            )}
                          </CardContent>
                        </Card>
                      );
                    })}
                  </div>

                  {/* Account statistics */}
                  <div className="mt-8 p-4 bg-slate-50 rounded-lg border border-slate-200">
                    <h3 className="font-medium text-slate-900 mb-2">Connection Status</h3>
                    <div className="flex items-center gap-4 text-sm text-slate-600">
                      <span>Connected: {socialAccounts.length}/4 platforms</span>
                      <span>•</span>
                      <span>Ready for automated posting</span>
                    </div>
                  </div>
                </div>
              </div>
            ) : view === 'media' ? (
              <div className="p-6 h-full overflow-y-auto">
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <div>
                      <h2 className="text-xl font-semibold text-slate-900 mb-2">Media Library</h2>
                      <p className="text-slate-600">Upload and manage your images and videos for content creation.</p>
                    </div>
                    <ObjectUploader
                      maxNumberOfFiles={1}
                      maxFileSize={10485760} // 10MB
                      onGetUploadParameters={handleGetUploadParameters}
                      onComplete={handleUploadComplete}
                      buttonClassName="flex items-center gap-2"
                    >
                      <Upload className="h-4 w-4" />
                      Upload Media
                    </ObjectUploader>
                  </div>

                  {/* Media Grid */}
                  {mediaLoading ? (
                    <div className="text-center py-12">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-slate-900 mx-auto"></div>
                      <p className="text-slate-600 mt-2">Loading media...</p>
                    </div>
                  ) : mediaLibrary.length === 0 ? (
                    <div className="text-center py-12">
                      <Image className="h-12 w-12 text-slate-400 mx-auto mb-4" />
                      <h3 className="text-lg font-semibold text-slate-900 mb-2">No media files yet</h3>
                      <p className="text-slate-600 mb-4">Upload your first image or video to get started</p>
                      <ObjectUploader
                        maxNumberOfFiles={1}
                        maxFileSize={10485760}
                        onGetUploadParameters={handleGetUploadParameters}
                        onComplete={handleUploadComplete}
                        buttonClassName="mx-auto"
                      >
                        <div className="flex items-center gap-2">
                          <Upload className="h-4 w-4" />
                          Upload Your First Media
                        </div>
                      </ObjectUploader>
                    </div>
                  ) : (
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-4">
                      {mediaLibrary.map((media: MediaLibrary) => {
                        const isImage = media.mimeType?.startsWith('image/');
                        const isVideo = media.mimeType?.startsWith('video/');

                        return (
                          <Card key={media.id} className="group relative overflow-hidden hover:shadow-lg transition-all">
                            <div className="aspect-square relative bg-slate-100">
                              {isImage ? (
                                <img
                                  src={media.url}
                                  alt={media.filename}
                                  className="w-full h-full object-cover"
                                  onError={(e) => {
                                    (e.target as HTMLImageElement).style.display = 'none';
                                    (e.target as HTMLImageElement).nextElementSibling!.classList.remove('hidden');
                                  }}
                                />
                              ) : isVideo ? (
                                <video
                                  src={media.url}
                                  className="w-full h-full object-cover"
                                  muted
                                  onError={(e) => {
                                    (e.target as HTMLVideoElement).style.display = 'none';
                                    (e.target as HTMLVideoElement).nextElementSibling!.classList.remove('hidden');
                                  }}
                                />
                              ) : null}

                              {/* Fallback display */}
                              <div className="hidden w-full h-full flex items-center justify-center">
                                <div className="text-center">
                                  <Image className="h-8 w-8 text-slate-400 mx-auto mb-2" />
                                  <p className="text-xs text-slate-500">{media.filename}</p>
                                </div>
                              </div>

                              {/* Overlay with actions */}
                              <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-30 transition-all flex items-center justify-center opacity-0 group-hover:opacity-100">
                                <div className="flex gap-2">
                                  <Button
                                    size="sm"
                                    variant="secondary"
                                    className="bg-white text-slate-900 hover:bg-slate-100"
                                    onClick={() => window.open(media.url, '_blank')}
                                    data-testid={`view-media-${media.id}`}
                                  >
                                    <ExternalLink className="h-3 w-3" />
                                  </Button>
                                  <Button
                                    size="sm"
                                    variant="destructive"
                                    onClick={() => handleDeleteMedia(media.id)}
                                    disabled={deleteMediaMutation.isPending}
                                    data-testid={`delete-media-${media.id}`}
                                  >
                                    <Trash2 className="h-3 w-3" />
                                  </Button>
                                </div>
                              </div>

                              {/* File type indicator */}
                              {isVideo && (
                                <div className="absolute top-2 right-2 bg-black bg-opacity-50 text-white text-xs px-2 py-1 rounded">
                                  VIDEO
                                </div>
                              )}
                            </div>

                            <CardContent className="p-3">
                              <div className="space-y-1">
                                <p className="text-sm font-medium text-slate-900 truncate" title={media.filename}>
                                  {media.filename}
                                </p>
                                <div className="flex items-center justify-between text-xs text-slate-500">
                                  <span>{media.mimeType}</span>
                                  <span>{formatFileSize(media.size)}</span>
                                </div>
                                <p className="text-xs text-slate-400">
                                  {media.createdAt ? format(new Date(media.createdAt), 'MMM d, yyyy') : 'Unknown date'}
                                </p>
                              </div>
                            </CardContent>
                          </Card>
                        );
                      })}
                    </div>
                  )}

                  {/* Media Statistics */}
                  {mediaLibrary.length > 0 && (
                    <div className="mt-8 p-4 bg-slate-50 rounded-lg border border-slate-200">
                      <h3 className="font-medium text-slate-900 mb-2">Library Stats</h3>
                      <div className="flex items-center gap-4 text-sm text-slate-600">
                        <span>Total files: {mediaLibrary.length}</span>
                        <span>•</span>
                        <span>Images: {mediaLibrary.filter((m: MediaLibrary) => m.mimeType?.startsWith('image/')).length}</span>
                        <span>•</span>
                        <span>Videos: {mediaLibrary.filter((m: MediaLibrary) => m.mimeType?.startsWith('video/')).length}</span>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="p-6 space-y-4 h-full overflow-y-auto">
                {filteredContent.length === 0 ? (
                  <div className="text-center py-12">
                    <CalendarIcon className="h-12 w-12 text-slate-400 mx-auto mb-4" />
                    <h3 className="text-lg font-semibold text-slate-900 mb-2">No content found</h3>
                    <p className="text-slate-600 mb-4">Get started by creating your first post</p>
                    <Button onClick={() => setShowCreateDialog(true)}>
                      <Plus className="h-4 w-4 mr-2" />
                      Create Post
                    </Button>
                  </div>
                ) : (
                  <div className="grid gap-4">
                    {filteredContent.map((post: Content) => {
                      const platformInfo = getPlatformInfo(post.platform);
                      return (
                        <Card key={post.id} className="hover:shadow-md transition-shadow">
                          <CardHeader className="pb-3">
                            <div className="flex items-start justify-between">
                              <div className="flex items-center gap-3">
                                <div className={`w-3 h-3 rounded-full ${platformInfo.color}`} />
                                <div>
                                  <CardTitle className="text-lg">{post.title}</CardTitle>
                                  <div className="flex items-center gap-2 mt-1">
                                    <Badge variant={getStatusBadgeVariant(post.status)}>
                                      {post.status}
                                    </Badge>
                                    <span className="text-sm text-slate-500">{platformInfo.label}</span>
                                    {post.scheduledFor && (
                                      <span className="text-sm text-slate-500">
                                        • {format(new Date(post.scheduledFor), 'MMM d, h:mm a')}
                                      </span>
                                    )}
                                  </div>
                                </div>
                              </div>
                              <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                  <Button variant="ghost" size="sm">
                                    <MoreHorizontal className="h-4 w-4" />
                                  </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent>
                                  <DropdownMenuItem onClick={() => {
                                    setSelectedPost(post);
                                    setFormData({
                                      title: post.title,
                                      body: post.body,
                                      platform: post.platform,
                                      contentType: post.contentType,
                                      pillar: post.pillar,
                                      goal: post.goal,
                                      scheduledFor: post.scheduledFor ? new Date(post.scheduledFor) : undefined,
                                    });
                                    setShowCreateDialog(true);
                                  }}>
                                    Edit
                                  </DropdownMenuItem>
                                  <DropdownMenuItem 
                                    onClick={() => handleDeletePost(post.id)}
                                    className="text-red-600"
                                  >
                                    Delete
                                  </DropdownMenuItem>
                                </DropdownMenuContent>
                              </DropdownMenu>
                            </div>
                          </CardHeader>
                          <CardContent>
                            <p className="text-slate-700 line-clamp-3">{post.body}</p>
                            {post.pillar && (
                              <div className="mt-3">
                                <Badge variant="outline" className="text-xs">
                                  {post.pillar}
                                </Badge>
                              </div>
                            )}
                          </CardContent>
                        </Card>
                      );
                    })}
                  </div>
                )}
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
}

