import { useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useAuth } from "@/hooks/useAuth";
import Sidebar from "@/components/sidebar";
import DailyFocusBanner from "@/components/daily-focus-banner";
import TodaysTasks from "@/components/todays-tasks";
import AISuggestions from "@/components/ai-suggestions";
import WeeklyProgress from "@/components/weekly-progress";
import QuickStats from "@/components/quick-stats";
import QuickActions from "@/components/quick-actions";
import TomorrowPreview from "@/components/tomorrow-preview";

interface DashboardProps {
  onSearchClick?: () => void;
}

export default function Dashboard({ onSearchClick }: DashboardProps) {
  const { toast } = useToast();
  const { isAuthenticated, isLoading, user } = useAuth();

  // Redirect to onboarding if brand DNA is not set up
  const { data: brandDna, isLoading: brandDnaLoading } = useQuery({
    queryKey: ["/api/brand-dna"],
    retry: false,
  });

  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, toast]);

  // Redirect to onboarding if no brand DNA
  useEffect(() => {
    if (!brandDnaLoading && !brandDna) {
      window.location.href = "/onboarding";
    }
  }, [brandDna, brandDnaLoading]);

  if (isLoading || brandDnaLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center mx-auto mb-4">
            <span className="text-white font-bold text-sm">N</span>
          </div>
          <p className="text-slate-600">Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50">
      <Sidebar onSearchClick={onSearchClick} />

      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 px-6 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-slate-900">
                Good morning, {user?.firstName || 'there'} 👋
              </h1>
              <p className="text-slate-600 mt-1">
                Today's focus: <span className="text-primary font-medium">Visibility & Trust Building</span>
              </p>
            </div>
            <div className="flex items-center space-x-4">
              <button className="relative p-2 text-slate-400 hover:text-slate-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-5 5v-5zM11 19H6a2 2 0 01-2-2V7a2 2 0 012-2h5a2 2 0 012 2v5" />
                </svg>
                <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full text-xs text-white flex items-center justify-center">2</span>
              </button>
            </div>
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto p-6">
          <div className="max-w-7xl mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Left Column */}
              <div className="lg:col-span-2 space-y-6">
                <DailyFocusBanner />
                <TodaysTasks />
                <AISuggestions />
              </div>

              {/* Right Column */}
              <div className="space-y-6">
                <WeeklyProgress />
                <QuickStats />
                <QuickActions />
                <TomorrowPreview />
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}

