client/src/pages/onboarding.tsx.content:
import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { z } from "zod";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Progress } from "@/components/ui/progress";
import { ArrowLeft, ArrowRight } from "lucide-react";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

const onboardingSchema = z.object({
  // Business Identification
  businessName: z.string().min(1, "Please enter your business name"),
  website: z.string().optional(),
  linkedinProfile: z.string().optional(),
  instagramHandle: z.string().optional(),

  // Section 1: Business Intelligence
  businessType: z.string().min(1, "Please select your business type"),
  businessModel: z.string().min(1, "Please select your business model"),
  revenueUrgency: z.string().min(1, "Please select your revenue situation"),

  // Section 2: Audience Psychology
  targetAudience: z.string().min(1, "Please select your target audience"),
  corePainPoint: z.string().min(1, "Please select the core pain point"),
  audienceAspiration: z.string().min(1, "Please select audience aspiration"),

  // Section 3: Brand Positioning
  authorityLevel: z.string().min(1, "Please select your authority level"),
  communicationStyle: z.string().min(1, "Please select your communication style"),
  uniquePositioning: z.string().min(10, "Please describe your unique positioning"),

  // Section 4: Platform Strategy
  platformPriority: z.string().min(1, "Please select your platform priority"),
  currentPresence: z.string().min(1, "Please select your current presence"),

  // Section 5: Goals & Timeline
  primaryGoal: z.string().min(1, "Please select your primary goal"),
  contentBandwidth: z.string().min(1, "Please select your content bandwidth"),
  successDefinition: z.string().min(1, "Please select your success definition"),

  // Bonus Questions (Optional)
  currentChallenges: z.string().optional(),
  pastSuccess: z.string().optional(),
  inspiration: z.string().optional(),
});

type OnboardingFormData = z.infer<typeof onboardingSchema>;

const sections = [
  { title: "🏢 Business Information", description: "Tell us about your business and online presence" },
  { title: "🎯 Business Intelligence", description: "Your business foundation and model" },
  { title: "👤 Audience Psychology", description: "Who are you serving and what do they need?" },
  { title: "🗣️ Brand Positioning", description: "How do you want to be positioned in the market?" },
  { title: "📱 Platform Strategy", description: "Where will you connect with your audience?" },
  { title: "🎯 Goals & Timeline", description: "What are you trying to achieve?" },
  { title: "🧬 Bonus Insights", description: "Additional context to supercharge your strategy" },
];

export default function Onboarding() {
  const { toast } = useToast();
  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = sections.length;

  const form = useForm<OnboardingFormData>({
    resolver: zodResolver(onboardingSchema),
    defaultValues: {
      businessName: "",
      website: "",
      linkedinProfile: "",
      instagramHandle: "",
      businessType: "",
      businessModel: "",
      revenueUrgency: "",
      targetAudience: "",
      corePainPoint: "",
      audienceAspiration: "",
      authorityLevel: "",
      communicationStyle: "",
      uniquePositioning: "",
      platformPriority: "",
      currentPresence: "",
      primaryGoal: "",
      contentBandwidth: "",
      successDefinition: "",
      currentChallenges: "",
      pastSuccess: "",
      inspiration: "",
    },
  });

  const saveBrandDna = useMutation({
    mutationFn: async (data: OnboardingFormData) => {
      await apiRequest("POST", "/api/brand-dna", data);
    },
    onSuccess: () => {
      toast({
        title: "Welcome to Naya!",
        description: "Your strategic profile is complete. Let's start building your empire.",
      });
      window.location.href = "/";
    },
    onError: (error) => {
      toast({
        title: "Setup Failed",
        description: "There was an error saving your profile. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: OnboardingFormData) => {
    console.log("🚀 Form submitted! Data:", data);
    console.log("📋 Form state:", form.formState);
    console.log("❌ Form errors:", form.formState.errors);
    saveBrandDna.mutate(data);
  };

  const nextStep = () => {
    setCurrentStep(prev => Math.min(prev + 1, totalSteps));
  };

  const prevStep = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  };

  const progress = (currentStep / totalSteps) * 100;

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <Card className="w-full max-w-3xl">
        <CardHeader className="text-center">
          <div className="flex items-center justify-center space-x-3 mb-4">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <span className="text-white font-bold text-sm">N</span>
            </div>
            <span className="text-xl font-bold text-slate-900">Naya</span>
          </div>
          <CardTitle className="text-2xl">Your AI Business Co-Pilot Setup</CardTitle>
          <CardDescription>
            {sections[currentStep - 1].description}
          </CardDescription>
          <div className="space-y-2 mt-4">
            <div className="flex justify-between text-sm text-slate-500">
              <span>Step {currentStep} of {totalSteps}</span>
              <span>{Math.round(progress)}% Complete</span>
            </div>
            <Progress value={progress} className="w-full" />
          </div>
        </CardHeader>

        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">

              {/* Section 1: Business Information */}
              {currentStep === 1 && (
                <div className="space-y-6">
                  <div className="text-center">
                    <h3 className="text-lg font-semibold mb-2">{sections[0].title}</h3>
                    <p className="text-sm text-slate-600">Help Naya research your online presence and identify strategic opportunities</p>
                  </div>

                  <FormField
                    control={form.control}
                    name="businessName"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Business Name *</FormLabel>
                        <FormControl>
                          <Input placeholder="e.g., Smith Marketing Consulting" {...field} />
                        </FormControl>
                        <FormDescription>
                          Your business or personal brand name. This helps Naya analyze your market position.
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="website"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Website (Optional)</FormLabel>
                        <FormControl>
                          <Input placeholder="https://yourwebsite.com" {...field} />
                        </FormControl>
                        <FormDescription>
                          Your main website. Naya will analyze your online presence and content strategy.
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="linkedinProfile"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>LinkedIn Profile (Optional)</FormLabel>
                        <FormControl>
                          <Input placeholder="https://linkedin.com/in/yourprofile" {...field} />
                        </FormControl>
                        <FormDescription>
                          Your LinkedIn profile URL. Essential for B2B strategy and authority building.
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="instagramHandle"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Instagram Handle (Optional)</FormLabel>
                        <FormControl>
                          <Input placeholder="@yourbusiness" {...field} />
                        </FormControl>
                        <FormDescription>
                          Your Instagram handle. Important for visual branding and B2C engagement.
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              )}

              {/* Section 2: Business Intelligence */}
              {currentStep === 2 && (
                <div className="space-y-6">
                  <div className="text-center">
                    <h3 className="text-lg font-semibold mb-2">{sections[1].title}</h3>
                    <p className="text-sm text-slate-600">Strategic Framework Database + Success Pattern Matching</p>
                  </div>

                  <FormField
                    control={form.control}
                    name="businessType"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>What type of business do you run?</FormLabel>
                        <FormControl>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <SelectTrigger>
                              <SelectValue placeholder="Select your business type" />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="b2b_consulting">B2B Consulting (strategy, marketing, operations)</SelectItem>
                              <SelectItem value="b2b_creative">B2B Creative Services (design, copywriting, development)</SelectItem>
                              <SelectItem value="b2c_coaching">B2C Coaching (business, life, health, relationships)</SelectItem>
                              <SelectItem value="b2c_products">B2C Products (physical products, e-commerce)</SelectItem>
                              <SelectItem value="digital_products">Digital Products (courses, templates, software)</SelectItem>
